"""
MKT Christ-in-Every-Verse Commentary — Genesis chapters 4–6
Run: python3 scripts/zc-christ-genesis-4-6.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-christ/genesis.json (existing: chs 1–3 complete)

Key Christological decisions:
- Abel's blood (4:10) / Heb 12:24: treated as a type with explicit NT warrant —
  Abel's blood cries for vengeance; Christ's blood speaks a better word (forgiveness).
- Lamech's song (4:23–24) / Matt 18:21–22: the seventy-seven vengeance vs.
  Christ's seventy-seven forgiveness is the most direct NT reversal of Genesis 4.
- Enoch's translation (5:24) / Heb 11:5: treated as a type of resurrection — the
  first person in Scripture to escape death, pointing to Christ's resurrection and
  the believers' ultimate translation.
- Noah's name (5:29): treated as a type — Lamech's hope for a comforter from the
  curse is partially fulfilled in the flood's reset, but only fully in Christ who
  bears the curse (Gal 3:13) and gives true rest (Matt 11:28–30).
- 'kopher' (pitch/covering, 6:14): cognate with 'kipper' (atone/cover) — defensible
  lexical connection; the covering that saves from the flood anticipates atoning
  coverage. 1 Pet 3:20–21 provides the explicit NT warrant for ark typology.
- First covenant (6:18): the berit with Noah is the foundation of the covenant
  sequence that climaxes in the new covenant through Christ (Heb 12:24).
- Genealogy entries (5:4–27): brief entries noting the death refrain — the dominant
  Christological point is that every patriarch dies, pointing toward the one who
  breaks the death cycle (1 Cor 15:20–22).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-christ commentary for Genesis 4–6. These chapters move from the
#   first murder (4) to the first genealogy and its death refrain (5) to the
#   flood narrative set-up and first covenant (6). The Christological center is
#   the blood of Abel (Heb 12:24), Enoch's translation (Heb 11:5), Noah's grace
#   (Eph 2:8 trajectory), and the ark as a type of salvation (1 Pet 3:20–21).
# CHANGE? If data/commentary/mkt-christ/genesis.json schema changes, update
#   load_comm/save_comm in Z_COMMENTARY_SCRIPT_GUIDE.md accordingly.
# VERIFY: After running, python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/genesis.json')); print(len(d.get('4',{})), len(d.get('5',{})), len(d.get('6',{})))" should print "26 32 22".

NEW_DATA = {
"4": {
"1": "<p>Eve&#8217;s exclamation at Cain&#8217;s birth &#8212; &#8220;With the help of the LORD I have brought forth a man&#8221; &#8212; reflects the hope that the promised seed of Genesis 3:15 has arrived. Whether she believed this literally or simply expressed joy with divine credit, the verse sets the pattern for the entire genealogical narrative: every birth after the fall is shadowed by the hope of the one who will crush the serpent. The theme is established here and threads through every subsequent birth announcement until &#8220;the fullness of time came, and God sent his Son, born of a woman&#8221; (Gal 4:4). The waiting for the right birth begins with the first.</p>",
"2": "<p>Abel is a keeper of flocks &#8212; a shepherd. The shepherd motif in Scripture runs directly to Christ: &#8220;I am the good shepherd; the good shepherd lays down his life for the sheep&#8221; (John 10:11). Abel, the righteous shepherd who will die, is the shadow of the one who calls himself the Good Shepherd. The pattern &#8212; shepherd, righteous, killed &#8212; is established in Abel and fulfilled in Christ, who is also &#8220;that great Shepherd of the sheep&#8221; (Heb 13:20) brought back from the dead through the blood of the eternal covenant.</p>",
"3": "<p>Cain brings &#8220;some of the fruits of the soil&#8221; &#8212; an offering without specification of quality, firstfruits, or blood. The verse establishes the principle that appears throughout Levitical law and culminates in Christ: God is not indifferent to the manner of approach. The theme of acceptable versus unacceptable sacrifice runs from here through the entire sacrificial system to Heb 10:1&#8211;14, which argues that the animal sacrifices were never the real thing &#8212; only Christ&#8217;s sacrifice is the offering God ultimately accepts, the one that removes sin rather than merely covering it year by year.</p>",
"4": "<p>Abel&#8217;s offering &#8212; fat portions from the firstborn of his flock &#8212; is accepted. The firstborn and the fat are the choicest parts, the portions that Levitical law would later require for sacrifice (Lev 3:16; 4:31). Heb 11:4 says &#8220;by faith Abel brought God a better offering&#8221; &#8212; the better offering is a type: blood is shed, the firstborn dies, the fat (life-force) is given. The NT sees this as the template that Christ fulfills &#8212; &#8220;our Passover lamb has been sacrificed&#8221; (1 Cor 5:7). The firstborn of the flock that Abel offers prefigures the firstborn of creation who offers himself (Col 1:15; Heb 12:23).</p>",
"5": "<p>Cain&#8217;s offering is not accepted, and his anger and fallen countenance mark the beginning of sin&#8217;s second-generation consequences. The rejection of his worship is not arbitrary but rooted in the character of what was brought and the heart behind it (1 John 3:12 &#8212; &#8220;Cain, who belonged to the evil one and murdered his brother. And why did he murder him? Because his own actions were evil and his brother&#8217;s were righteous&#8221;). The theme of God&#8217;s righteous discrimination between genuine and counterfeit worship is resolved in Christ, whose offering is the only one God accepts unconditionally (Heb 10:14 &#8212; &#8220;by one sacrifice he has made perfect forever those who are being made holy&#8221;).</p>",
"6": "<p>&#8220;Why are you angry?&#8221; God speaks to the sin-angry Cain with a question rather than immediate judgment &#8212; the pastoral patience of a seeking God. The same God who walks in the garden calling &#8220;Where are you?&#8221; (3:9) now speaks into Cain&#8217;s anger rather than abandoning him. This reveals the character of the God who will be expressed fully in Christ: &#8220;God did not send his Son into the world to condemn the world, but to save the world through him&#8221; (John 3:17). Divine rebuke and divine mercy are inseparable in both testaments.</p>",
"7": "<p>&#8220;Sin is crouching at your door; it desires to have you, but you must rule over it.&#8221; The personification of sin as a crouching predator anticipates the NT&#8217;s treatment of sin as a power that enslaves. Paul in Rom 6 picks up this language: sin &#8220;reigns&#8221; over those who yield to it, but Christ breaks that reign. The command &#8220;you must rule over it&#8221; is what fallen humanity cannot do in its own strength (Rom 7:15&#8211;24); it is what Christ does perfectly, and what he empowers his people to do through the Spirit (Rom 8:13). The crouching sin that Cain failed to master is the power Christ defeats and enables his people to resist (1 Cor 10:13).</p>",
"8": "<p>Cain kills Abel &#8212; the first murder in Scripture. The NT draws two Christological threads from Abel&#8217;s death. First, Abel is the paradigm of the righteous one killed by the wicked (Matt 23:35 &#8212; &#8220;righteous Abel&#8221; as the first in the chain of martyred prophets). Second and more directly, Heb 12:24 contrasts the blood of Abel with the blood of Christ: Abel&#8217;s blood &#8220;cries out&#8221; (v10) for vengeance; the blood of Jesus &#8220;speaks a better word than the blood of Abel&#8221; &#8212; the better word is forgiveness rather than retribution. Cain&#8217;s fratricide is the act that gives Abel&#8217;s blood its typological weight.</p>",
"9": "<p>&#8220;Am I my brother&#8217;s keeper?&#8221; The question that Cain dismisses is the question Christ answers with his life. Christ is his brothers&#8217; keeper in every sense: &#8220;I am the good shepherd; I know my sheep&#8221; (John 10:14); &#8220;He is able to save completely those who come to God through him, because he always lives to intercede for them&#8221; (Heb 7:25). The theme of keeper/guardian runs through Num 6:24 (&#8220;the LORD keep you&#8221;), Ps 121:5 (&#8220;the LORD watches over you&#8221;), and is embodied in Christ who keeps his own from perishing (John 10:28). Cain&#8217;s denial is the anti-type of Christ&#8217;s self-giving care.</p>",
"10": "<p>&#8220;Your brother&#8217;s blood cries out to me from the ground.&#8221; The blood of a murdered innocent demands justice from the Creator. Heb 12:24 makes the Christological application explicit: Christ has come to &#8220;the sprinkled blood that speaks a better word than the blood of Abel.&#8221; Abel&#8217;s blood cried for vengeance; Christ&#8217;s blood &#8212; applied like the Passover blood, sprinkled like the covenant blood (Exod 24:8) &#8212; speaks the better word of forgiveness and peace. The blood that cries from the ground in Gen 4 is the type; the blood sprinkled from the cross is the antitype that silences sin&#8217;s accusation and satisfies justice with mercy.</p>",
"11": "<p>Cain is cursed from the ground &#8212; the same ground cursed in 3:17, now doubly cursed because it has drunk his brother&#8217;s blood. The escalating curse pattern &#8212; creation, ground, Cain &#8212; is the trajectory that Christ reverses. Gal 3:13 &#8212; &#8220;Christ redeemed us from the curse of the law by becoming a curse for us&#8221; &#8212; applies to the entire curse structure inaugurated in Genesis 3&#8211;4. The driven wanderer and the cursed ground are both part of what Christ absorbs and reverses at the cross.</p>",
"12": "<p>&#8220;You will be a restless wanderer on the earth.&#8221; The exile from land and rest is the consequence of Cain&#8217;s sin &#8212; and the condition of fallen humanity more broadly. Christ&#8217;s invitation in Matt 11:28&#8211;30 is addressed precisely to this condition: &#8220;Come to me, all you who are weary and burdened, and I will give you rest.&#8221; The promised rest of the Sabbath (2:3) that sin interrupts is restored in Christ &#8212; not as geographic settlement but as the Sabbath-rest that remains for the people of God (Heb 4:9). The restless wandering of Cain&#8217;s curse is answered by the rest Christ offers.</p>",
"13": "<p>&#8220;My punishment is more than I can bear.&#8221; Cain&#8217;s lament reveals the crushing weight of guilt and judgment. The theme of bearing what cannot be borne is central to atonement theology: Christ bears what humanity cannot &#8212; &#8220;Surely he took up our pain and bore our suffering&#8221; (Isa 53:4); &#8220;The LORD has laid on him the iniquity of us all&#8221; (Isa 53:6). What Cain says he cannot bear, Christ bears on behalf of all who are guilty. The one who says &#8220;it is more than I can bear&#8221; is answered by the one who says &#8220;Come to me, and I will give you rest&#8221; (Matt 11:28).</p>",
"14": "<p>&#8220;I will be hidden from your presence.&#8221; The exile from the face of God is sin&#8217;s deepest penalty. Christ&#8217;s cry from the cross &#8212; &#8220;My God, my God, why have you forsaken me?&#8221; (Matt 27:46; Ps 22:1) &#8212; is the moment when the Son of God enters the divine absence that sin deserves. What Cain fears &#8212; being hidden from God&#8217;s presence &#8212; is what Christ voluntarily undergoes in order to bring his people back into the divine presence. The fear of divine exile in v14 is answered by Christ&#8217;s prayer that his people will be with him where he is (John 17:24).</p>",
"15": "<p>God places a protective mark on Cain to prevent others from killing him. The impulse behind the mark is divine mercy restraining the cycle of violence. The mark of protection echoes forward through Scripture: Ezek 9:4&#8211;6 uses the same language of a protective mark for the faithful who grieve Jerusalem&#8217;s sin; Rev 7:3 and 9:4 describe God&#8217;s seal on the servants of God protecting them from judgment. Christ is the ultimate seal and protector: &#8220;now it is God who makes both us and you stand firm in Christ. He anointed us, set his seal of ownership on us, and put his Spirit in our hearts as a deposit&#8221; (2 Cor 1:21&#8211;22). God&#8217;s mercy even to the murderer prefigures the mercy that flows through the cross.</p>",
"16": "<p>Cain leaves the LORD&#8217;s presence and settles &#8220;east of Eden.&#8221; The eastward movement &#8212; away from the garden, away from God &#8212; is established as the direction of exile in Genesis (3:24; 4:16; 11:2). The entire biblical narrative is a movement from east back toward the divine presence. Christ is the one who makes the return possible: &#8220;I am the way and the truth and the life. No one comes to the Father except through me&#8221; (John 14:6). The geography of exile established here is the geography that Christ&#8217;s redemption reverses.</p>",
"17": "<p>Cain builds a city &#8212; named for his son Enoch &#8212; the first human city in Scripture. The Cainite city represents human civilization without God: built on murder, organized for self-sufficiency. It stands in contrast to the city God prepares &#8212; &#8220;the city with foundations, whose architect and builder is God&#8221; (Heb 11:10), the &#8220;holy city, the new Jerusalem, coming down out of heaven from God&#8221; (Rev 21:2). Christ is both the foundation of the true city (1 Cor 3:11) and the Lamb in its midst (Rev 21:22). The human city built for human glory is the shadow that the heavenly city makes obsolete.</p>",
"18": "<p>The Cainite genealogy &#8212; Enoch to Lamech &#8212; is the line of human civilization developing outside of God&#8217;s presence. As a genealogical list, its direct Christological content is minimal; as a literary parallel to the Sethite line (vv25&#8211;26 and ch5), it marks the fork in the road: one line leads away from God toward Lamech&#8217;s vengeance-culture; the other leads toward Noah, then Abraham, then David, then Christ. The two lines of Genesis 4 set up the central tension of the entire OT: the line of the promised seed vs. the line of violent human self-assertion.</p>",
"19": "<p>Lamech takes two wives &#8212; the first bigamy in Scripture. The departure from the one-flesh union of Genesis 2:24 signals the further distortion of the created order in the Cainite line. The theme of marriage as the covenant relationship between one man and one woman is preserved through the OT and restored in Christ, who embodies the one true groom for his bride the church (Eph 5:25&#8211;32). The distortion of marriage that begins with Lamech is the opposite of the marriage of the Lamb (Rev 19:7); Christ restores what sin here begins to destroy.</p>",
"20": "<p>Jabal, father of those who live in tents and raise livestock &#8212; a founder of pastoral civilization. Even this cultural gift, attributed to the Cainite line, reflects the common grace through which God sustains human society after the fall. Christ as the one through whom &#8220;all things were created&#8221; (Col 1:16) is the ultimate source of all human creativity and culture; the gifts developed in the Cainite line are not abandoned by God but will ultimately be redeemed and brought into the new creation (Rev 21:24 &#8212; &#8220;the glory and honor of the nations&#8221; brought into the city).</p>",
"21": "<p>Jubal, father of music &#8212; stringed instruments and pipes. Like Jabal&#8217;s pastoral gifts, the gift of music comes through the Cainite line under common grace. Music&#8217;s ultimate destination is the worship of God: &#8220;they were singing a new song before the throne&#8221; (Rev 14:3); &#8220;with gratitude sing to God with your hearts&#8221; (Col 3:16). Christ himself sang hymns with his disciples (Matt 26:30); Heb 2:12 applies Ps 22:22 to Christ: &#8220;I will sing your praises in the presence of the congregation.&#8221; The music that begins with Jubal finds its true purpose when directed to Christ and the God who sent him.</p>",
"22": "<p>Tubal-Cain, forger of bronze and iron &#8212; the inventor of metalworking, including weapons. The same technology that enables building and cultivation also enables greater violence &#8212; prefiguring Lamech&#8217;s boast that follows. The eschatological hope reverses this: &#8220;They will beat their swords into plowshares and their spears into pruning hooks&#8221; (Isa 2:4; Mic 4:3). Christ is the Prince of Peace (Isa 9:6) who will ultimately convert the weapons of violence into tools of flourishing. Tubal-Cain&#8217;s metalwork points toward what it will become when Christ reigns.</p>",
"23": "<p>Lamech&#8217;s sword-song is the apex of the Cainite line&#8217;s self-assertion &#8212; unlimited, boastful vengeance: &#8220;I have killed a man for wounding me.&#8221; The spirit of Cain escalates to its logical extreme. Christ directly reverses Lamech&#8217;s arithmetic in Matt 18:21&#8211;22: when Peter asks about forgiving seven times, Jesus says &#8220;not seven times, but seventy-seven times&#8221; &#8212; the exact number of Lamech&#8217;s revenge-boast (v24), now deployed as the measure of forgiveness. The song of limitless vengeance is the anti-gospel that the gospel of limitless forgiveness explicitly overturns.</p>",
"24": "<p>&#8220;If Cain is avenged seven times, then Lamech seventy-seven times.&#8221; The escalation from seven to seventy-seven marks the degeneration of the Cainite culture of violence. Matt 18:22 is the precise inversion: &#8220;I tell you, not seven times, but seventy-seven times&#8221; &#8212; Christ redeploys Lamech&#8217;s number as the measure of forgiveness. This is the direct answer to the logic of Lamech: where Lamech multiplied vengeance to seventy-seven, Christ commands forgiveness to seventy-seven. The gospel does not merely correct the spirit of Lamech; it arithmetically reverses his formula.</p>",
"25": "<p>Seth is born as God&#8217;s &#8220;appointed&#8221; replacement for Abel &#8212; the line of promise continues despite Cain&#8217;s murder. Seth is in the direct genealogical line of Christ: Luke 3:38 traces Jesus&#8217; descent through &#8220;Seth, the son of Adam, the son of God.&#8221; The promise of the seed of the woman (3:15) did not die with Abel; God provided another son. The theme of divine provision of an unexpected heir &#8212; Seth for Abel, Isaac for Ishmael, Jacob for Esau &#8212; runs through Genesis and culminates in the unexpected heir, Christ, born to a virgin in Bethlehem. God&#8217;s purposes cannot be murdered out of the world.</p>",
"26": "<p>&#8220;At that time people began to call on the name of the LORD.&#8221; The beginning of corporate worship is the first gospel recovery after the fall &#8212; calling on the divine name. Joel 2:32 promises: &#8220;everyone who calls on the name of the LORD will be saved&#8221; &#8212; and Peter quotes this at Pentecost to define the scope of Christ&#8217;s salvation (Acts 2:21). Paul applies it directly to Christ in Rom 10:13: &#8220;everyone who calls on the name of the Lord will be saved.&#8221; The corporate calling on the LORD&#8217;s name that begins with Seth&#8217;s generation is the act that the NT applies to faith in Christ. The call that began here is the call that saves.</p>"
},
"5": {
"1": "<p>&#8220;This is the written account of Adam&#8217;s family line.&#8221; Matthew opens his Gospel with &#8220;A record of the genealogy of Jesus the Messiah&#8221; &#8212; the word is <em>genesis</em>, directly echoing the Genesis toledot formula. The genealogical chain that begins with Adam in God&#8217;s likeness terminates in Christ, who is the true image of God (Col 1:15; 2 Cor 4:4) and the &#8220;last Adam&#8221; (1 Cor 15:45). This verse is the opening of the genealogical record that leads, through Seth to Noah to Abraham to David, directly to Christ. The account of Adam&#8217;s line is the account of the family into which the Son of God will be born.</p>",
"2": "<p>God created them male and female &#8212; the echo of 1:27 within the genealogical frame. The blessing of fruitfulness given to the original pair is the blessing that the Abrahamic line carries forward and that Christ fulfills in his gathering of a people from every nation (Matt 28:19; Rev 7:9). The &#8220;they&#8221; of creation &#8212; male and female together bearing the image &#8212; is the humanity that Christ assumes and redeems. Gal 3:28 &#8212; &#8220;there is neither male nor female, for you are all one in Christ Jesus&#8221; &#8212; is the restoration of the original unity implied in this verse.</p>",
"3": "<p>Adam fathers Seth &#8220;in his own likeness, in his own image.&#8221; The contrast with 1:27 is significant: humanity was created in God&#8217;s image, but Seth is born in Adam&#8217;s image &#8212; the image now carries the distortion of sin. Every human born after the fall inherits the fallen image of Adam rather than the pure image of God. This is the condition Paul describes in 1 Cor 15:49: &#8220;just as we have borne the image of the earthly man&#8221; &#8212; but the verse continues &#8212; &#8220;so shall we bear the image of the heavenly man,&#8221; i.e., Christ. The solution to the distorted image is conformity to the image of the Son (Rom 8:29).</p>",
"4": "<p>Adam lives 800 years after Seth&#8217;s birth and has other sons and daughters. The scale of Adam&#8217;s life spans centuries &#8212; an unimaginable expanse of time before the approaching death refrain. The theme established by this genealogy is the creeping approach of death to every life: Christ enters this genealogy as the one who &#8220;has destroyed death and has brought life and immortality to light through the gospel&#8221; (2 Tim 1:10). The long centuries of antediluvian life make the eventual death more striking; Christ&#8217;s defeat of the final enemy (1 Cor 15:26) is the answer to what the genealogy announces.</p>",
"5": "<p>&#8220;Altogether, Adam lived a total of 930 years, and then he died.&#8221; The death refrain that echoes through Genesis 5 is the most insistent commentary on the fall&#8217;s consequence &#8212; &#8220;you shall surely die&#8221; (2:17). Every patriarch, however long-lived, dies. Paul&#8217;s argument in 1 Cor 15:21&#8211;22 is built on this: &#8220;since death came through a man, the resurrection of the dead comes also through a man. For as in Adam all die, so in Christ all will be made alive.&#8221; The &#8220;and then he died&#8221; that haunts every genealogy entry is the problem Christ&#8217;s resurrection definitively solves.</p>",
"6": "<p>Seth fathers Enosh at 105 years. Enosh&#8217;s name means &#8220;mortal&#8221; or &#8220;frail man&#8221; &#8212; the consciousness of human frailty is embedded in the name of this generation. The theme of human mortality and frailty reaches its answer in Christ who took on this mortal frailty (Heb 2:14 &#8212; sharing in the children&#8217;s humanity) in order to &#8220;free those who all their lives were held in slavery by their fear of death.&#8221; The name Enosh is a tacit acknowledgement of the condition Christ addresses.</p>",
"7": "<p>Seth lives 807 years after Enosh&#8217;s birth. The long years between each patriarch&#8217;s son and his death mark the unhurried unfolding of the genealogy that leads to Christ. The passage of time in this genealogy is the passage of time Scripture calls &#8220;the fullness of time&#8221; &#8212; when everything was in place for God to send his Son (Gal 4:4). The long genealogy is the long patience of God waiting for the right moment in history.</p>",
"8": "<p>&#8220;And then he died.&#8221; The refrain for Seth. Each repetition of the death refrain is a data point in the argument that Christ&#8217;s resurrection will answer: &#8220;The last enemy to be destroyed is death&#8221; (1 Cor 15:26). The genealogy of death is the problem statement; the resurrection of Christ is the solution. These brief death notices are the repeated diagnosis that the gospel addresses.</p>",
"9": "<p>Enosh fathers Kenan at 90 years. The chain continues &#8212; each link in the genealogy is a link in the chain from Adam to Christ. Luke 3:37&#8211;38 includes Kenan in the genealogy of Jesus. Every name in this list is a link in the ancestry of the one through whom God fulfills every promise made since the fall. The genealogy is the story of God&#8217;s faithfulness across the long centuries between the fall and the incarnation.</p>",
"10": "<p>Enosh lives 815 years after Kenan&#8217;s birth. The extended lifespans of the antediluvian period are part of the pre-flood world that 2 Pet 3:6 distinguishes from the present age. The world before the flood had a different character; the great ages underscore both the antiquity of the line and the patience of God who preserved it across these vast spans. The God who preserved Enosh&#8217;s line for 905 years is the same God who will preserve his church until Christ returns.</p>",
"11": "<p>&#8220;And then he died.&#8221; The refrain for Enosh. Three deaths named in succession &#8212; Adam, Seth, Enosh &#8212; establish that neither longevity, nor godliness (Seth&#8217;s line calls on the LORD, 4:26), nor the passing of time reverses the curse of 2:17. Christ is the one who reverses it: &#8220;death has been swallowed up in victory&#8221; (1 Cor 15:54; Isa 25:8). The swallowing-up of death is the answer to the swallowing-up of every patriarch by death that this chapter records.</p>",
"12": "<p>Kenan fathers Mahalalel at 70 years. The genealogical chain continues toward the flood and beyond toward Abraham. Luke 3:37 includes Kenan in Christ&#8217;s ancestry. The names in this genealogy are not incidental &#8212; they are the family history of the Son of God. As Matthew&#8217;s genealogy opens &#8220;the genealogy of Jesus the Messiah&#8221; (Matt 1:1), these ancient names are part of the same story, the long family tree from Adam to the one who will bear the names of God himself (Isa 9:6).</p>",
"13": "<p>Kenan lives 840 years after Mahalalel&#8217;s birth. The vast spans of antediluvian life contrast starkly with the post-flood reduction in lifespan and ultimately with Christ&#8217;s 33 years on earth. The one who is eternal &#8212; &#8220;before Abraham was, I am&#8221; (John 8:58) &#8212; entered time as a mortal man with a brief lifespan, shorter than any of the patriarchs, to accomplish what centuries of long-lived humanity could not: the defeat of death itself.</p>",
"14": "<p>&#8220;And then he died.&#8221; The refrain for Kenan. The death refrain is not monotonous &#8212; it is accumulative, building the theological case that Paul makes explicit in Rom 5:12: &#8220;death spread to all people, because all sinned.&#8221; Each death in the genealogy is evidence for Paul&#8217;s argument. The same Paul who uses this genealogical reality to argue for universal death also argues that Christ&#8217;s resurrection is the universal answer: &#8220;so in Christ all will be made alive&#8221; (1 Cor 15:22).</p>",
"15": "<p>Mahalalel fathers Jared at 65 years. The name Mahalalel means &#8220;praise of God&#8221; &#8212; even in the genealogy of death, a name of worship persists. The praise-name amid the death refrain is a small echo of the hope that runs through the entire OT &#8212; that praise will outlast death. Rev 5:12&#8211;13 shows the ultimate fulfillment: the redeemed singing praise to the Lamb forever. The praise embedded in this genealogy anticipates the unending praise of Christ in the new creation.</p>",
"16": "<p>Mahalalel lives 830 years after Jared&#8217;s birth. The long years accumulate. The genealogy is moving toward Enoch &#8212; the single exception in the death refrain &#8212; whose translation from death foreshadows the resurrection that Christ brings. The reader who knows the genealogy begins to sense the approach of the exceptional case that breaks the pattern, as the exceptional resurrection of Christ breaks the pattern of universal death.</p>",
"17": "<p>&#8220;And then he died.&#8221; The refrain for Mahalalel. The pattern holds for every patriarch: even those who live nearly a millennium die. The pattern will not be broken by longevity or by name-meaning (Mahalalel &#8212; praise of God). It is broken only by divine action: in Enoch&#8217;s case by divine translation (v24), and definitively in Christ&#8217;s case by resurrection from the dead. The relentless refrain prepares for the relief of Enoch and the final relief of Christ&#8217;s resurrection.</p>",
"18": "<p>Jared fathers Enoch at 162 years. Enoch &#8212; the one who will not die &#8212; is coming. The approach of the exceptional name in the death genealogy is itself a small anticipation of the approach of the one who will definitively break the death pattern. Christ comes at the end of a genealogy much like this one (Matt 1) as the one who will break what the genealogy records. Enoch is a partial preview; Christ is the full answer.</p>",
"19": "<p>Jared lives 800 years after Enoch&#8217;s birth. The years between Enoch&#8217;s birth and the next patriarch&#8217;s birth continue the long slow movement of redemptive history. The God who is patient across 800 years is the same God who, &#8220;in the fullness of time&#8221; (Gal 4:4), sent his Son. The long patience of the genealogy is the patience of divine purpose &#8212; not slowness but deliberateness, as 2 Pet 3:9 says: &#8220;the Lord is not slow in keeping his promise, as some understand slowness.&#8221;</p>",
"20": "<p>&#8220;And then he died.&#8221; The refrain for Jared. The death that holds every patriarch will not hold Christ. Jared dies; but Enoch, born to Jared, will not. The contrast within a single father-son pair &#8212; Jared dies, Enoch does not &#8212; is the pattern at the largest scale: all in Adam die; all in Christ will be made alive. The single exception in the genealogy previews the categorical reversal that Christ brings.</p>",
"21": "<p>Enoch fathers Methuselah at 65 years. Methuselah&#8217;s name may mean &#8220;man of the spear&#8221; or possibly &#8220;when he dies, judgment comes&#8221; &#8212; a rabbinic tradition holds that the flood came the year Methuselah died. Whether or not this is exact, Methuselah&#8217;s extraordinary lifespan (969 years, the longest in the Bible) and his connection to the flood narrative make him a marker of God&#8217;s patience. 2 Pet 3:9 &#8212; &#8220;He is patient with you, not wanting anyone to perish, but everyone to come to repentance&#8221; &#8212; is the principle Methuselah&#8217;s long life embodies. God delays judgment for the sake of the elect.</p>",
"22": "<p>&#8220;Enoch walked faithfully with God 300 years.&#8221; The language of walking with God &#8212; <em>hithhallek &#699;et-hāʾĕlōhîm</em> &#8212; echoes the pre-fall communion of Eden and anticipates the restored fellowship Christ brings. The same phrase is used of Noah (6:9). Walking with God is the condition Christ restores: &#8220;we walk by faith, not by sight&#8221; (2 Cor 5:7); &#8220;walk in the Spirit&#8221; (Gal 5:16). The fellowship with God that Enoch enjoyed &#8212; &#8220;then he was no more, because God took him&#8221; &#8212; prefigures the unbroken communion with God that Christ secures for all who are in him (John 17:24).</p>",
"23": "<p>&#8220;Altogether, Enoch lived a total of 365 years.&#8221; Enoch&#8217;s years match the days in a solar year &#8212; a detail that has attracted notice across the centuries, though its significance is disputed. The brevity of Enoch&#8217;s life relative to his contemporaries (Methuselah lived 969 years) underlines that what matters is not longevity but faithfulness. Christ&#8217;s earthly life was shorter still &#8212; roughly 33 years &#8212; yet his is the life that gives life to the world (John 6:33). Quality of communion with God, not quantity of years, is what the genealogy commends in Enoch&#8217;s case.</p>",
"24": "<p>&#8220;Enoch walked faithfully with God; then he was no more, because God took him away.&#8221; The single exception in the death-genealogy. Heb 11:5 makes the Christological application explicit: &#8220;By faith Enoch was taken from this life, so that he did not experience death.&#8221; Enoch&#8217;s translation is the first glimpse in Scripture of life beyond death &#8212; a type of the resurrection that Christ brings and that believers share. As Enoch was &#8220;taken&#8221; (Gen 5:24 LXX: <em>metatithēmi</em>), so Paul uses the cognate <em>metaschēmatizō</em> for the transformation at the resurrection (1 Cor 15:51&#8211;52). The one death-refrain that doesn&#8217;t come is the first preview of Christ&#8217;s permanent abolition of death.</p>",
"25": "<p>Methuselah fathers Lamech &#8212; this Lamech is in the Sethite line, distinct from the violent Lamech of ch4. The same name in different lines marks the fork in the narrative: one Lamech produces the sword-song of unlimited vengeance; this Lamech produces Noah. The God who works through ordinary, named generations in ordinary family lines is the same God who will ultimately work through Mary of Nazareth to bring his Son into the world. Redemptive history moves through family lines &#8212; God&#8217;s method is genealogy.</p>",
"26": "<p>Methuselah lives 782 years after Lamech&#8217;s birth &#8212; 969 years total (v27), the longest life in the Bible. Methuselah&#8217;s great age, in Jewish tradition, marks the patience of God before the flood. 2 Pet 3:9 &#8212; &#8220;The Lord is not slow in keeping his promise, as some understand slowness. Instead he is patient with you, not wanting anyone to perish&#8221; &#8212; is the principle that Methuselah&#8217;s extraordinary lifespan illustrates. The patience that delays judgment is the same patience behind the cross: Christ&#8217;s coming was precisely timed for maximum redemptive effect (Rom 5:6 &#8212; &#8220;at just the right time, Christ died for the ungodly&#8221;).</p>",
"27": "<p>&#8220;And then he died.&#8221; Even Methuselah &#8212; the longest-lived human in Scripture &#8212; dies. The death refrain claims the one who lived longest. No quantity of years defeats death; only the resurrection of Christ does. &#8220;For since death came through a man, the resurrection of the dead comes also through a man&#8221; (1 Cor 15:21). The longest life in the genealogy still ends in death, underscoring that the solution is not more life of the same kind but a different kind of life altogether &#8212; the resurrection life that Christ is and gives (John 11:25).</p>",
"28": "<p>Lamech fathers a son. The anticipation builds toward Noah&#8217;s naming in v29, where Lamech&#8217;s hope for relief from the curse is explicitly articulated. The naming-hope of v29 is the most explicitly Messianic moment in the Genesis 5 genealogy: a human voice, mid-genealogy, naming a child for the relief that only God can give. It is the cry of creation groaning for redemption (Rom 8:22) in genealogical form.</p>",
"29": "<p>&#8220;He will comfort us in the labor and painful toil of our hands caused by the ground the LORD has cursed.&#8221; Lamech&#8217;s naming-hope for Noah is a type: Noah will bring relief from the curse through the flood&#8217;s reset and the post-flood covenant. But the relief is partial &#8212; the ground is still cursed after the flood. The full comfort awaits Christ. Matt 11:28&#8211;30 &#8212; &#8220;Come to me, all you who are weary and burdened, and I will give you rest&#8221; &#8212; is the answer to Lamech&#8217;s hope. Gal 3:13 &#8212; &#8220;Christ redeemed us from the curse of the law by becoming a curse for us&#8221; &#8212; is the theological answer to the specific curse Lamech names. Noah is the type; Christ is the comfort.</p>",
"30": "<p>Lamech lives 595 years after Noah&#8217;s birth. The lifespan that follows the birth of the child of hope continues the genealogical chain. Each year of Lamech&#8217;s post-Noah life is a year of waiting for the promise his naming-hope expressed. The waiting of the patriarchs is the waiting of all humanity for the one Lamech named &#8212; the one who will truly comfort and relieve. Christ&#8217;s coming ends the long waiting of the genealogy.</p>",
"31": "<p>&#8220;And then he died.&#8221; The death refrain claims Lamech &#8212; the father who hoped for a comforter. Even the man who named his son for relief dies before seeing the full comfort he hoped for. This is the pattern of the OT saints: &#8220;These were all commended for their faith, yet none of them received what had been promised&#8221; (Heb 11:39). They saw the promise from a distance and welcomed it; the full comfort they named in their children came only in Christ.</p>",
"32": "<p>&#8220;After Noah was 500 years old, he became the father of Shem, Ham and Japheth.&#8221; The three sons of Noah are the ancestors of all post-flood humanity &#8212; the table of nations in Genesis 10 traces the seventy nations from this threefold origin. Christ redeems from every nation: &#8220;You are worthy to take the scroll and to open its seals, because you were slain, and with your blood you purchased for God persons from every tribe and language and people and nation&#8221; (Rev 5:9). Shem, Ham, and Japheth are the origin of every tribe and nation from which Christ gathers his people.</p>"
},
"6": {
"1": "<p>Human multiplication across the earth &#8212; the fruitfulness mandate of 1:28 operating, but in the context of the post-fall world. The growth of population is not itself evil, but it amplifies the reach of human sin. Luke 17:26&#8211;27 uses the days of Noah as a picture of the end times: &#8220;People were eating, drinking, marrying and being given in marriage up to the day Noah entered the ark. Then the flood came and destroyed them all.&#8221; The ordinary-life obliviousness before the flood is the template for the obliviousness before Christ&#8217;s return. As the flood came unexpectedly on a multiplying humanity, so Christ&#8217;s return will come on the world in its ordinary busyness.</p>",
"2": "<p>The &#8220;sons of God&#8221; take the daughters of humans &#8212; whatever the exact identity of the <em>bĕnê hāʾĕlōhîm</em> (debated: divine beings, Sethites, or rulers/tyrants), the narrative describes a crossing of boundaries that God established and the further corruption of the created order. The episode illustrates the penetration of sin through every realm &#8212; human, social, possibly cosmic &#8212; that Christ&#8217;s redemption must address. Col 1:20 &#8212; &#8220;through him to reconcile to himself all things, whether things on earth or things in heaven&#8221; &#8212; is the scope of Christ&#8217;s reconciling work that matches the scope of the corruption here described.</p>",
"3": "<p>&#8220;My Spirit will not contend with humans forever, for they are mortal.&#8221; God&#8217;s Spirit limits the time of grace before judgment. The same Spirit poured out at Pentecost without limit (Acts 2:17 &#8212; &#8220;I will pour out my Spirit on all people&#8221;) is the Spirit whose contending with humanity here has an expiration. Christ sends the Spirit to plead with the world (John 16:8 &#8212; &#8220;he will convict the world of guilt&#8221;) &#8212; but the contending has a limit. The Spirit&#8217;s withdrawal in judgment here anticipates the final sealing of judgment when Christ returns and the age of grace closes.</p>",
"4": "<p>The Nephilim &#8212; the &#8220;fallen ones&#8221; or giants &#8212; and the &#8220;heroes of old, men of renown&#8221; represent the ultimate human arrogance: claiming divine-scale power and reputation in defiance of God. The pride of the Nephilim stands against the humility of Christ: &#8220;he did not consider equality with God something to be grasped, but made himself nothing&#8221; (Phil 2:6&#8211;7). The men of renown who claim greatness through power are the anti-type of the servant-king who became great through self-emptying and obedience. Christ undoes the logic of the Nephilim by establishing a new and opposite definition of greatness (Matt 20:26&#8211;28).</p>",
"5": "<p>&#8220;Every inclination of the thoughts of the human heart was only evil all the time.&#8221; The diagnosis of total depravity before the flood is the same condition Paul diagnoses in Rom 3:10&#8211;18 &#8212; a catena of OT texts establishing that there is no one righteous, not even one. The flood is the OT&#8217;s answer to total corruption; the gospel is the NT&#8217;s answer. Christ comes to address the same condition that made the flood necessary: &#8220;What a wretched man I am! Who will rescue me from this body that is subject to death? Thanks be to God, who delivers me through Jesus Christ our Lord!&#8221; (Rom 7:24&#8211;25). The every-inclination-only-evil of v5 is the problem Christ&#8217;s death and the Spirit&#8217;s renewal address.</p>",
"6": "<p>&#8220;The LORD regretted that he had made human beings on the earth, and his heart was deeply troubled.&#8221; The divine grief (<em>nāḥam</em> &#8212; the same root as Noah&#8217;s name) over sin&#8217;s devastation is the emotion that will find its fullest expression in the incarnate Son: &#8220;he was a man of sorrows and familiar with suffering&#8221; (Isa 53:3); &#8220;Jesus wept&#8221; (John 11:35) over sin&#8217;s consequences. The God who is grieved by human sin in v6 is the same God who enters human grief in Christ &#8212; not as a distant observer but as one who bears the grief himself. Divine sorrow over sin is not a contradiction of divine love but its deepest expression.</p>",
"7": "<p>God&#8217;s declaration of judgment &#8212; &#8220;I will wipe from the face of the earth the human race I have created.&#8221; The flood is a type of the final judgment that Christ will execute. 2 Pet 3:5&#8211;7 makes the comparison explicit: &#8220;By these waters also the world of that time was deluged and destroyed. By the same word the present heavens and earth are reserved for fire, being kept for the day of judgment.&#8221; The flood judges the pre-Christ world; Christ will judge the world at his return. Acts 17:31 &#8212; &#8220;he has set a day when he will judge the world with justice by the man he has appointed.&#8221; The flood previews the final judgment; Christ executes both the rescue and the judgment it foreshadows.</p>",
"8": "<p>&#8220;But Noah found favor (<em>ḥēn</em>) in the eyes of the LORD.&#8221; The first use of &#8220;grace&#8221; in the Bible. The <em>ḥēn</em> &#8212; undeserved favor &#8212; that rescues Noah from the flood is the principle that runs to its fullest expression in Eph 2:8&#8211;9: &#8220;it is by grace you have been saved, through faith &#8212; and this is not from yourselves, it is the gift of God.&#8221; As Noah did nothing to earn the flood&#8217;s escape but received divine favor, so believers are saved not by works but by grace through Christ. The &#8220;but Noah found favor&#8221; against the backdrop of universal human corruption is the structure of every gospel: unearned grace selecting one from among the condemned.</p>",
"9": "<p>Noah was &#8220;righteous, blameless among the people of his time,&#8221; and &#8220;walked faithfully with God.&#8221; Three epithets that carry Christological freight. Righteous (<em>ṣaddîq</em>): Christ is the Righteous One (Acts 3:14; 7:52; 1 John 2:1) whose righteousness is credited to believers (Rom 4:5). Blameless (<em>tāmîm</em>): the same word used for the unblemished Passover lamb (Exod 12:5); Christ is the &#8220;lamb without blemish or defect&#8221; (1 Pet 1:19). Walking with God: the restored communion that Christ brings (John 14:6 &#8212; &#8220;no one comes to the Father except through me&#8221;). Noah&#8217;s three epithets are a shadow of what Christ is in fullness and truth.</p>",
"10": "<p>Noah&#8217;s three sons &#8212; Shem, Ham, and Japheth &#8212; are the post-flood source of all humanity. Genesis 10&#8217;s table of nations traces seventy nations from these three sons. Christ&#8217;s redemption gathers from every nation: &#8220;you purchased for God persons from every tribe and language and people and nation&#8221; (Rev 5:9). The scope of Noah&#8217;s family as the origin of all nations is the scope of Christ&#8217;s redemptive reach. The seventy nations of Genesis 10 match the seventy disciples Jesus sends out in Luke 10:1 &#8212; the mission of Christ is explicitly to the scope of the nations descending from Noah&#8217;s sons.</p>",
"11": "<p>&#8220;The earth was corrupt in God&#8217;s sight and was full of violence (<em>ḥāmās</em>).&#8221; The corruption and violence that fills the pre-flood earth is the condition into which God sends his Son &#8212; &#8220;he came to what was his own, but his own did not receive him&#8221; (John 1:11). Christ enters the violent, corrupt world not to condemn it (John 3:17) but to take its violence upon himself (Isa 53:9 &#8212; &#8220;though he had done no violence&#8221;, he bore violent death). The world of v11 is the world that the cross addresses: God reconciling to himself the violent and corrupt world he made.</p>",
"12": "<p>&#8220;All the people on earth had corrupted their ways.&#8221; The universal scope of corruption &#8212; every person, every path distorted &#8212; is the diagnosis that makes the gospel necessary. Paul&#8217;s argument in Rom 1&#8211;3 moves through the same logic: all have sinned (Rom 3:23), none righteous, therefore the righteousness of God through faith in Christ is the only remedy. The flood is the OT response to universal corruption; the cross is the definitive response. Christ does not merely reset the world as the flood did; he provides the new creation that does not revert to the corruption the flood temporarily interrupted.</p>",
"13": "<p>God speaks judgment and salvation to Noah simultaneously &#8212; &#8220;I am going to put an end to all people&#8230; So make yourself an ark.&#8221; The same divine word announces destruction and provides escape. This is the pattern of the gospel: &#8220;whoever does not believe stands condemned already&#8221; (John 3:18), but Christ is the provision of escape from the condemnation. God does not leave Noah without warning or provision; he does not leave the world without warning or provision either &#8212; Christ is the ark of refuge from the coming judgment (John 5:24 &#8212; &#8220;whoever hears my word and believes him who sent me has eternal life and will not be judged&#8221;).</p>",
"14": "<p>The ark made of <em>gōper</em>-wood, coated inside and out with <em>kōper</em> (pitch or bitumen). The Hebrew word <em>kōper</em> shares its consonantal root with <em>kipper</em> (to cover/atone), the root of <em>kappōret</em> (the mercy seat) and <em>Yom Kippur</em> (Day of Atonement). The covering that protects Noah from the flood judgment is linguistically linked to the covering that protects Israel from divine wrath on the Day of Atonement &#8212; and both point toward Christ. 1 Pet 3:20&#8211;21 explicitly draws the ark-to-Christ line: &#8220;in the ark&#8230; only a few people were saved through water, and this water symbolizes baptism that now saves you also &#8212; by the resurrection of Jesus Christ.&#8221; The covering of the ark is the type of the atonement Christ provides.</p>",
"15": "<p>The precise dimensions of the ark &#8212; 300 by 50 by 30 cubits &#8212; signal a real, constructed vessel, not a symbol. The ark&#8217;s dimensions have been compared to seaworthy vessels by marine architects &#8212; the ratio of length to breadth is within the range of modern ship design. The physicality of the ark matters: salvation through Christ is not mythological but historical. As the ark was a real vessel in which real people survived a real judgment, so Christ&#8217;s death was a real death in real history that accomplishes real atonement. The physical specificity of the ark corresponds to the physical specificity of the cross.</p>",
"16": "<p>The <em>ṣōhar</em> &#8212; a roof opening or light-source &#8212; is built into the ark, along with a single door. The one door of the ark is a type: &#8220;I am the gate; whoever enters through me will be saved&#8221; (John 10:9). As there was one way into the ark &#8212; through the single door &#8212; there is one way to salvation through the flood of divine judgment: through Christ. Augustine made this connection; the NT logic of Christ as the exclusive way (John 14:6) gives it its warrant. The single door of the ark is the single door of the gospel.</p>",
"17": "<p>God announces the flood &#8212; &#8220;everything on earth will perish.&#8221; The comprehensive scope of the judgment is what makes the ark&#8217;s rescue comprehensive for those inside. The logic of salvation through Christ follows the same pattern: the scope of death is the scope of Christ&#8217;s rescue &#8212; &#8220;as in Adam all die, so in Christ all will be made alive&#8221; (1 Cor 15:22). The universal death sentence of the flood is the type of the universal death sentence under sin that makes the universal offer of rescue through Christ both necessary and gracious.</p>",
"18": "<p>&#8220;But I will establish my covenant with you.&#8221; The first use of <em>bĕrît</em> (covenant) in the Bible. This Noahic covenant is the first in the chain: Noahic &#8594; Abrahamic &#8594; Mosaic &#8594; Davidic &#8594; New Covenant. Each covenant in the chain escalates and clarifies what God is doing; the New Covenant through Christ is the fulfillment of all. Heb 12:24 &#8212; &#8220;Jesus the mediator of a new covenant&#8221; &#8212; stands at the end of the covenant chain that begins here. The God who makes covenants &#8212; binding himself by oath to preserve his people through judgment &#8212; is the God who sends his Son as the covenant guarantee (Heb 7:22 &#8212; &#8220;Jesus has become the guarantor of a better covenant&#8221;).</p>",
"19": "<p>Two of every creature into the ark &#8212; preservation of the created order through the judgment. The scope of salvation is not merely human but creational: God preserves the creatures he made. The new creation that Christ brings is similarly creational in scope: &#8220;creation itself will be liberated from its bondage to decay and brought into the freedom and glory of the children of God&#8221; (Rom 8:21). The ark&#8217;s preservation of animals through the flood is the type of the new creation&#8217;s preservation and renewal of the whole created order through Christ&#8217;s redemption.</p>",
"20": "<p>Every kind of bird and animal coming to the ark to be kept alive &#8212; the creatures responding to the divine summons. The gathering of all kinds of creatures around the saving vessel anticipates the eschatological gathering: &#8220;all nations will be gathered before him&#8221; (Matt 25:32); &#8220;every tribe and language and people and nation&#8221; redeemed by Christ (Rev 5:9). The ark that gathered every kind of living creature is the type of the gospel that gathers every kind of human being: &#8220;Go into all the world and preach the gospel to all creation&#8221; (Mark 16:15). The scope of the ark&#8217;s gathering is the scope of Christ&#8217;s mission.</p>",
"21": "<p>God commands food to be stored in the ark &#8212; provision for the journey through judgment. The God who provides food in the ark is the God who provides manna in the wilderness and who, in Christ, declares himself &#8220;the bread of life&#8221; (John 6:35) &#8212; the provision that sustains his people through every trial. The ark is provisioned for survival; Christ&#8217;s people are provisioned with &#8220;every spiritual blessing in Christ&#8221; (Eph 1:3). The stored food of the ark points toward the spiritual sustenance Christ supplies to those who shelter in him through the judgment of sin and death.</p>",
"22": "<p>&#8220;Noah did everything just as God commanded him.&#8221; The perfect obedience of Noah is a type of the perfect obedience of Christ. Heb 11:7 frames Noah&#8217;s obedience as faith: &#8220;by faith Noah, when warned about things not yet seen, in holy fear built an ark to save his family.&#8221; Christ&#8217;s obedience is greater: &#8220;he humbled himself by becoming obedient to death &#8212; even death on a cross&#8221; (Phil 2:8). Noah obeyed God&#8217;s command to build; Christ obeyed the Father&#8217;s will to die. Rom 5:19 &#8212; &#8220;through the obedience of the one man the many will be made righteous&#8221; &#8212; is the ultimate statement of which Noah&#8217;s complete obedience is the shadow. Noah did everything God commanded; Christ did everything the Father required &#8212; and his obedience becomes the righteousness of all who are in him.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'genesis')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-christ', 'genesis', existing)
    print(f"  ch4 verses: {len(existing.get('4', {}))}")
    print(f"  ch5 verses: {len(existing.get('5', {}))}")
    print(f"  ch6 verses: {len(existing.get('6', {}))}")
    print("Genesis 4–6 mkt-christ written.")

if __name__ == '__main__':
    main()
